  }
}];

const LABELS = {
  en: {
    'Invoice':                { label: 'Invoice',                description: 'Details of the amount to be paid for services or medications provided to the patient.' },
    'Payment Proof':          { label: 'Payment Proof',          description: 'Proof of payment completion such as a receipt or bank transfer.' },
