    'Medical Report':         { label: 'Medical Report',         description: 'A document explaining the patient health condition, diagnosis, and treatment.' },
    'Rad Report':             { label: 'Rad Report',             description: 'A radiological report for imaging tests such as X-rays or ultrasounds.' },
    'Lab Result':             { label: 'Lab Result',             description: 'A report showing the outcomes of medical tests or laboratory exams.' },
    'Itemized Invoice':       { label: 'Itemized Invoice',       description: 'An invoice that breaks down all services with their prices and quantities.' },
