    'Operation Note':         { label: 'Operation Note',         description: 'A note written by the surgeon after a surgical procedure.' },
    'Attendance Sheet':       { label: 'Attendance Sheet',       description: 'A record of attendance for medical sessions or appointments.' },
    'Schedule Of Service':    { label: 'Schedule Of Service',    description: 'A list of treatment sessions with dates and prices.' }
  },
