    'Invoice':                { label: 'فاتورة',                 description: 'تفاصيل المبلغ المستحق مقابل الخدمات أو الأدوية المقدمة للمريض.' },
    'Payment Proof':          { label: 'إثبات الدفع',            description: 'ما يثبت اكتمال الدفع المطلوب كإيصال أو تحويل بنكي.' },
    'Refraction Test Result': { label: 'نتيجة اختبار الانكسار', description: 'فحص يحدد قوة النظارات أو العدسات اللازمة لتصحيح الرؤية.' },
    'Receipt':                { label: 'إيصال',                  description: 'وثيقة تُظهر المبلغ المدفوع والخدمات التي يغطيها الدفع.' },
    'Prescription':           { label: 'وصفة طبية',              description: 'وثيقة من الطبيب تتضمن الأدوية الموصوفة وطريقة استخدامها.' },
    'Medical Report':         { label: 'تقرير طبي',              description: 'وثيقة تشرح الحالة الصحية للمريض والتشخيص والعلاج.' },
    'Rad Report':             { label: 'تقرير أشعة',             description: 'تقرير يشرح نتائج فحوصات التصوير كالأشعة السينية أو الموجات فوق الصوتية.' },
    'Lab Result':             { label: 'نتيجة المختبر',          description: 'تقرير يُظهر نتائج الفحوصات الطبية أو التحاليل المخبرية.' },
    'Itemized Invoice':       { label: 'فاتورة مفصّلة',          description: 'فاتورة تُفصّل جميع الخدمات مع أسعارها وكمياتها.' },
    'Discharge Summary':      { label: 'ملخص الخروج',            description: 'تقرير يُكتب عند مغادرة المريض للمستشفى.' },
    'Prior Approval':         { label: 'موافقة مسبقة',           description: 'إذن من شركة التأمين قبل تلقي علاج محدد.' },
    'Operation Note':         { label: 'ملاحظات العملية',        description: 'ملاحظات يكتبها الجراح بعد إجراء العملية الجراحية.' },
    'Attendance Sheet':       { label: 'سجل الحضور',             description: 'سجل بالحضور للجلسات الطبية أو المواعيد.' },
    'Schedule Of Service':    { label: 'جدول الخدمات',           description: 'قائمة بجلسات العلاج مع التواريخ والأسعار.' }
  }
};

const CLAIMS_LOGIC = {
  Optical:       { mandatory: ['Invoice', 'Payment Proof', 'Refraction Test Result'], optional: [] },
  Outpatient:    { mandatory: ['Invoice', 'Receipt', 'Prescription', 'Medical Report'], optional: ['Rad Report', 'Lab Result'] },
  Dental:        { mandatory: ['Medical Report', 'Payment Proof', 'Invoice'], optional: [] },
  Inpatient:     { mandatory: ['Itemized Invoice', 'Receipt'], optional: ['Rad Report', 'Discharge Summary', 'Prior Approval', 'Operation Note', 'Lab Result'] },
  Autism:        { mandatory: ['Attendance Sheet', 'Invoice', 'Medical Report', 'Schedule Of Service'], optional: ['Receipt', 'Prescription'] },
  ADHD:          { mandatory: ['Attendance Sheet', 'Invoice', 'Medical Report', 'Schedule Of Service'], optional: ['Receipt', 'Prescription'] },
  Physiotherapy: { mandatory: ['Attendance Sheet', 'Invoice', 'Medical Report', 'Schedule Of Service'], optional: ['Receipt', 'Prescription'] },
  Psychotherapy: { mandatory: ['Attendance Sheet', 'Invoice', 'Medical Report', 'Schedule Of Service'], optional: ['Receipt', 'Prescription'] }
};

const BENEFIT_NAMES = {
  en: { Optical: 'Optical', Outpatient: 'Out Patient', Dental: 'Dental', Inpatient: 'In Patient', Autism: 'Autism', ADHD: 'ADHD', Physiotherapy: 'Physiotherapy', Psychotherapy: 'Psychotherapy' },
  ar: { Optical: 'بصريات', Outpatient: 'عيادة خارجية', Dental: 'أسنان', Inpatient: 'تنويم', Autism: 'توحد', ADHD: 'اضطراب نقص الانتباه', Physiotherapy: 'علاج طبيعي', Psychotherapy: 'علاج نفسي' }
};

const body = $json.body || $json;
const benefitType = body.benefit_type || 'Outpatient';
const forDependentId = body.for_dependent_id ?? 'SELF';
const forDependentName = body.for_dependent_name ?? null;
const lang = $('Claim Init Trigger').first().json.body.language === 'ar' ? 'ar' : 'en';
const logic = CLAIMS_LOGIC[benefitType] || CLAIMS_LOGIC['Outpatient'];
const dict = LABELS[lang];
const benefitLabel = BENEFIT_NAMES[lang][benefitType] || benefitType;
const message = lang === 'ar'
  ? `يرجى رفع المستندات المطلوبة لمطالبة ${benefitLabel}.`
  : `Please upload the required documents for your ${benefitLabel} claim.`;

const required_docs = [
  ...logic.mandatory.map(type => ({ key: type, label: dict[type]?.label || type, description: dict[type]?.description || '', required: true })),
  ...logic.optional.map(type => ({ key: type, label: dict[type]?.label || type, description: dict[type]?.description || '', required: false }))
];

return [{
  json: {
    type: 'document_upload',
    message,
    benefit_type: benefitType,
    for_dependent_id: forDependentId,
    for_dependent_name: forDependentName,
    required_docs,
    resumeUrl: $execution.resumeUrl
  }
}];

const rawOcr = $input.first().json;
const result = Array.isArray(rawOcr) ? rawOcr[0] : rawOcr;

if (!result || result.status !== 'SUCCESS') {
  return [{
    json: {
      type: 'assistant_text',
      message: 'We could not process your documents. Please ensure they are clear and legible, then try again.',
      is_error: true
    }
  }];
}
function normalizeDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) return s; // already DD/MM/YYYY
  const iso = s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (iso) return `${iso[3]}/${iso[2]}/${iso[1]}`;  // YYYY-MM-DD → DD/MM/YYYY
  const MONTHS = { jan:'01',feb:'02',mar:'03',apr:'04',may:'05',jun:'06',
                   jul:'07',aug:'08',sep:'09',oct:'10',nov:'11',dec:'12' };
  const mon = s.match(/^(\d{1,2})[- ]([A-Za-z]{3})[- ](\d{4})$/);
  if (mon) {
    const m = MONTHS[mon[2].toLowerCase()];
    if (m) return `${String(mon[1]).padStart(2,'0')}/${m}/${mon[3]}`;
  }
  const dmy = s.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (dmy) return `${dmy[1]}/${dmy[2]}/${dmy[3]}`;  // DD-MM-YYYY → DD/MM/YYYY
  return s;
}

function parseDiagnosisCodes(raw) {
  if (!raw) return [];
  if (Array.isArray(raw)) return raw.map(String).filter(Boolean);
  // Split on newlines — each line is a full "CODE, Description (Primary|Secondary)"
  return String(raw).split(/\n+/).map(s => s.trim()).filter(Boolean);
}


const exec = result.execution_result;

// Collect image snippets for each field (only include fields that have one)
const image_snippets = {};
const SNIPPET_FIELDS = [
  'claimant_name', 'policy_number', 'provider_name', 'provider_country',
  'service_date', 'diagnosis_code', 'service_code', 'claim_amount',
  'VAT', 'deductible', 'claim_notes', 'benefit_category'
];
for (const field of SNIPPET_FIELDS) {
  const snippet = exec[field]?.image_snippet;
  if (snippet) image_snippets[field] = snippet;
}

return [{
  json: {
    type: 'extracted_form',
    message: 'We extracted your information. Please review and confirm.',
    extracted_data: {
      claimant_name:    exec.claimant_name?.value ?? null,
      policy_number:    exec.policy_number?.value ?? null,
      provider_name:    exec.provider_name?.value ?? null,
      provider_country: exec.provider_country?.value ?? null,
      service_date:     normalizeDate(exec.service_date?.value),
      diagnosis_code:   parseDiagnosisCodes(exec.diagnosis_code?.value),
      service_code:     exec.service_code?.value ?? null,
      claim_amount:     exec.claim_amount?.value ?? null,
      VAT:              exec.VAT?.value ?? null,
      deductible:       exec.deductible?.value ?? null,
      claim_notes:      exec.claim_notes?.value ?? null,
      benefit_category: exec.benefit_category?.value ?? null,
      image_snippets,           // ← ADD THIS
    },
    ocr_confidence: result.ocr_confidence ?? null,
    is_doc_unclear:  result.is_doc_unclear ?? false,
    resumeUrl: $execution.resumeUrl
}
  }
];

// STUB — replace with real policy check, geo-validation, and saved IBAN lookup
return [{
  json: {
    type: 'iban_input',
    message: 'Please provide your bank account IBAN for reimbursement.',
    geo_check_status: true,
    is_service_uncovered: false,
    benefit_category: ($('Wait — Benefit Type').first().json.body || $('Wait — Benefit Type').first().json).benefit_type || null,
    saved_ibans: [],
    resumeUrl: $execution.resumeUrl
  }
}];

// STUB — replace with real IBAN verification and financial calculation
const body = $json.body || $json;
return [{
  json: {
    type: 'financial_summary',
    iban_verified: true,
    estimated_payout: 0.00,
    processing_type: 'Standard',
    currency: 'SAR',
    claim_amount: 0.00,
    VAT: 0.00,
    deductible: 0.00,
    resumeUrl: $execution.resumeUrl
  }
}];

// STUB — replace with real claim submission to MG Core
const claimId = 'UCRN' + Date.now();
return [{
  json: {
    type: 'success_card',
    claim_id: claimId,
    submission_timestamp: new Date().toISOString(),
    processing_type: 'Standard',
    message: 'Your claim has been submitted successfully. You will receive updates in your notification centre.'
  }
}];
